Debounce delays invoking a function until a specified wait time has passed since its last call, which is useful for rate-limiting events like typing, resizing, or scrolling.

```javascript
function debounce(fn, wait = 300) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), wait);
  };
}

// Example usage:
const handleSearch = debounce((query) => {
  console.log('Searching for:', query);
}, 500);

handleSearch('a');
handleSearch('ap');
handleSearch('app'); // Only this call will log after 500ms of inactivity
```
